<div class="en">
<svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Two Tokenization Models Compared</text>
  <g font-family="sans-serif">
    <text x="160" y="55" fill="#4ade80" font-size="14" font-weight="700" text-anchor="middle">Issuer-Sponsored</text>
    <rect x="35" y="70" width="250" height="60" rx="10" fill="#1c1c1f" stroke="#4ade80" stroke-width="1.5"/>
    <text x="160" y="105" fill="#e4e4e7" font-size="13" text-anchor="middle">Company → registered transfer agent</text>
    <text x="160" y="150" fill="#71717a" font-size="18" text-anchor="middle">↓</text>
    <rect x="35" y="165" width="250" height="60" rx="10" fill="#1c1c1f" stroke="#4ade80" stroke-width="1.5"/>
    <text x="160" y="200" fill="#e4e4e7" font-size="13" text-anchor="middle">On-chain shareholder register</text>
    <text x="160" y="245" fill="#71717a" font-size="18" text-anchor="middle">↓</text>
    <rect x="35" y="260" width="250" height="60" rx="10" fill="#1c1c1f" stroke="#4ade80" stroke-width="1.5"/>
    <text x="160" y="288" fill="#4ade80" font-size="13" font-weight="700" text-anchor="middle">Token = legal share proof</text>
    <text x="160" y="308" fill="#a1a1aa" font-size="12" text-anchor="middle">Dividends + voting pass through</text>

    <text x="540" y="55" fill="#f87171" font-size="14" font-weight="700" text-anchor="middle">Third-Party (no consent)</text>
    <rect x="415" y="70" width="250" height="60" rx="10" fill="#1c1c1f" stroke="#f87171" stroke-width="1.5"/>
    <text x="540" y="105" fill="#e4e4e7" font-size="13" text-anchor="middle">Platform (Robinhood, Kraken, etc.)</text>
    <text x="540" y="150" fill="#71717a" font-size="18" text-anchor="middle">↓</text>
    <rect x="415" y="165" width="250" height="60" rx="10" fill="#1c1c1f" stroke="#f87171" stroke-width="1.5"/>
